    {
      "title": "Suggested Practical List (Class XI)",
      "unit_name": "Unit 2: Computational Thinking and Programming - I",
      "chapter_name": "Computational Thinking and Programming - I",
      "details": "Input welcome message, compare numbers, generate patterns using nested loops, series summation programs, check perfect/Armstrong/palindrome numbers, prime/composite check, Fibonacci series, GCD/LCM calculation, string character counting, list/tuple operations (swap elements, search), dictionary creation and filtering."
    },
