    {
      "title": "Report File + Viva (Class XII)",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
      "chapter_name": "Computational Thinking and Programming – 2",
      "details": "Minimum of 15 Python programs, minimum 5 sets of SQL queries using one or two tables, and minimum 4 programs based on Python-SQL connectivity."
    },
    {
      "title": "Suggested Practical List (Class XII) - File Handling",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
      "chapter_name": "Computational Thinking and Programming – 2",
      "details": "Read text file line by line, count vowels/consonants in files, remove lines containing 'a', create binary file for search/update operations, random number generator (dice simulation), implement stack using list."
    },
    {
      "title": "Suggested Practical List (Class XII) - CSV",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
