    },
    {
      "title": "Suggested Practical List (Class XII) - Database Management",
      "unit_name": "Unit 3: Database Management",
      "chapter_name": "Database Management",
      "details": "Create student table, implement ALTER, UPDATE, ORDER BY, DELETE commands. Perform GROUP BY operations to find min, max, sum, count, and average."
    },
    {
      "title": "Suggested Practical List (Class XII) - Python-SQL Integration",
      "unit_name": "Unit 3: Database Management",
      "chapter_name": "Database Management",
      "details": "Integrate SQL with Python by importing suitable module to perform database operations."
    }
  ]
